/* taxMgmtMapper.taxSmsListTaxNo */
SELECT TAX_NO.NEXTVAL AS TAX_NO
FROM DUAL

/* taxMgmtMapper.getTaxSmsSendList */ SELECT A.TAX_NO /* 제세공과금 NO */ , A.SUBJECT /* 제목 */ , A.SEND_CNT /* 발신건수 */ , NVL((SELECT ''||COUNT(*) FROM MSP_TAX_SMS_SEND_LIST B WHERE A.TAX_NO = B.TAX_NO AND TAX_RECV_TIME IS NOT NULL),'-') AS REPLY_CNT /* 회신건수 */ , TO_CHAR(TO_DATE(A.REQUEST_TIME,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI') AS REQUEST_TIME /* 예약전송일자 */ , TO_CHAR(TO_DATE(A.REQUEST_TIME,'YYYYMMDDHH24MISS'),'HH') AS REQUEST_HOUR /* 예약전송시간 */ , A.REGST_ID /* 등록자ID */ , FN_GET_USRNM(A.REGST_ID) AS REGST_NM /* 등록자 */ , TO_CHAR(A.REGST_TIME, 'YYYY-MM-DD HH24:MI:SS') AS REGST_TIME /* 등록시간 */ , A.TAX_TMP_ID /* 템플릿ID */ , A.TAX_USG_YN /* 사용여부 (R : 진행대기, S : 완료, F : 실패, N : 삭제) */ , A.KAKAO_YN /* 카카오여부 */ , A.ADDRESS_YN /* 주소여부 */ , A.AGENT_YN /* 법정대리인 문자발송 여부 */ , A.AGENT_TMP_ID /* 법정대리인 템플릿 ID */ FROM MSP_TAX_SMS_LIST A WHERE A.TAX_USG_YN != 'N'
AND TO_CHAR(TO_DATE(REQUEST_TIME,'YYYYMMDDHH24MISS'),'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUBJECT LIKE '%' || #{subject} || '%'
ORDER BY REQUEST_TIME DESC

SELECT 	COUNT(CONTRACT_NUM)
FROM	MSP_JUO_SUB_INFO
WHERE	CONTRACT_NUM = #{contractNum}

SELECT 	COUNT(CONTRACT_NUM)
FROM	MSP_TAX_SMS_SEND_LIST
WHERE	TAX_NO = #{taxNo}
AND CONTRACT_NUM = #{contractNum}

/* taxMgmtMapper.isTaxSmsDeleteAuth */
SELECT  DECODE(COUNT(*), 1, 'Y', 'N') RESULT
FROM    MSP_TAX_SMS_LIST
WHERE   TAX_NO = #{taxNo}
AND	REGST_ID = #{sessionUserId}

AND	TAX_USG_YN = 'R' 

AND	REQUEST_TIME  >  TO_CHAR(SYSDATE,'YYYYMMDD')

mapper.update:
/* taxMgmtMapper.deleteTaxSmsList */
UPDATE	MSP_TAX_SMS_LIST
SET	
	TAX_USG_YN = 'N'										/* 사용여부 */		
	, RVISN_ID = #{sessionUserId} 						/* 수정자이름 */
	, RVISN_DTTM = SYSDATE			   				/* 수정날짜 */
	, SEND_CNT = (SELECT COUNT(*) FROM MSP_TAX_SMS_SEND_LIST WHERE TAX_NO = #{taxNo})						
WHERE	TAX_NO = #{taxNo}	
AND	REGST_ID = #{sessionUserId}
AND	TAX_USG_YN = 'R'

