	 DELETE 
	 	FROM MSP_TAX_SMS_SEND_LIST
     WHERE TAX_NO = #{taxNo, jdbcType=VARCHAR}

mapper.update:
	 	 /* taxMgmtMapper.getTaxSendListCount */
	 	UPDATE MSP_TAX_SMS_LIST A
			SET A.SEND_CNT = 
    			(SELECT COUNT(*) FROM MSP_TAX_SMS_SEND_LIST B
       			 WHERE TAX_NO = #{taxNo, jdbcType=VARCHAR})
		WHERE A.TAX_NO = #{taxNo, jdbcType=VARCHAR}

mapper.select:
/* taxMgmtMapper.getTaxSendTaxType */
SELECT 
	MSG_TYPE AS MSG_TMP_ID
	,TEXT
FROM   MSP_SMS_TEMPLATE_MST 
WHERE  TEMPLATE_ID = #{taxTmpId}

/* taxMgmtMapper.getAgentSendTaxType */
SELECT 
	MSG_TYPE AS MSG_TMP_ID
	,TEXT AS AGENT_TEXT
FROM   MSP_SMS_TEMPLATE_MST 
WHERE  TEMPLATE_ID = #{agentTmpId}

/* taxMgmtMapper.getTaxSendKakaoYn */
SELECT DECODE(K_TEMPLATE_CODE, NULL, 'N', 'Y')  AS KAKAO_YN
FROM   MSP_SMS_TEMPLATE_MST 
WHERE  TEMPLATE_ID = #{taxTmpId}

/* taxMgmtMapper.getAgentSendKakaoYn */
SELECT DECODE(K_TEMPLATE_CODE, NULL, 'N', 'Y')  AS AGENT_KAKAO_YN
FROM   MSP_SMS_TEMPLATE_MST 
WHERE  TEMPLATE_ID = #{agentTmpId}

mapper.update:
 /* taxMgmtMapper.getTaxTmpCallBack */
 UPDATE MSP_TAX_SMS_LIST A
	SET A.TAX_SEND_CTN = (SELECT CALLBACK FROM  MSP_SMS_TEMPLATE_MST B WHERE TEMPLATE_ID = #{taxTmpId, jdbcType=VARCHAR})
	   ,A.TAX_TITLE = (SELECT SUBJECT FROM MSP_SMS_TEMPLATE_MST B WHERE TEMPLATE_ID = #{taxTmpId, jdbcType=VARCHAR})
	   ,A.TAX_TEXT = #{text}

			,A.AGENT_TEXT = #{agentText}

	WHERE A.TAX_NO = #{taxNo, jdbcType=VARCHAR}

